mapper.select:
SELECT CAST(id AS CHAR) AS id,
       uuid,
       CAST(amount AS CHAR) AS amount,
       type,
       status,
       remark,
       DATE_FORMAT(create_time, '%Y-%m-%d %H:%i:%s') AS createTime
FROM tb_wallet_income
WHERE driver_id = #{driverId}

    AND status = #{status}


    AND type = #{type}


    AND DATE(create_time) >= #{startDate}


    AND DATE(create_time) <= #{endDate}

ORDER BY create_time DESC
LIMIT #{start}, #{length}

SELECT COUNT(*)
FROM tb_wallet_income
WHERE driver_id = #{driverId}

    AND status = #{status}


    AND type = #{type}

mapper.update:
UPDATE tb_wallet_income
SET status = #{status}
WHERE uuid = #{uuid}
  AND driver_id = #{driverId}

